INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", "2020/07/31 12:00:00", 24001, 401, "アヤネ", 2, 0.0, "2030/12/17 14:59:59", 0.0, 0.0, 102301, 2, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", "2020/07/31 12:00:00", 24002, 402, "アヤネ", 2, 0.0, "2030/12/17 14:59:59", 2.21, 0.0, 102301, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", "2020/07/31 12:00:00", 24003, 403, "アヤネ", 2, 0.0, "2030/12/17 14:59:59", 0.0, 0.0, 102301, 2, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", "2020/07/31 12:00:00", 24004, 701, "アサヒ", 1, 0.0, "2030/12/17 14:59:59", 1.99, 0.0, 192201, 2, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", "2020/07/31 12:00:00", 24005, 702, "アサヒ", 2, 0.0, "2030/12/17 14:59:59", 2.21, 0.0, 192201, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", "2020/07/31 12:00:00", 24006, 703, "アサヒ", 1, 0.0, "2030/12/17 14:59:59", 3.33, 0.0, 192201, 2, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", "2020/07/31 12:00:00", 24007, 801, "部員３", 2, 0.0, "2030/12/17 14:59:59", 0.0, 0.0, 192301, 2, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", "2020/07/31 12:00:00", 24008, 802, "部員３", 2, 0.0, "2030/12/17 14:59:59", 2.68, 0.0, 192301, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", "2020/07/31 12:00:00", 24009, 803, "部員３", 2, 0.0, "2030/12/17 14:59:59", 0.0, 0.0, 192301, 2, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("やった！", "2020/07/31 12:00:00", 24010, 501, "", 1, 0.0, "2030/12/17 14:59:59", 0.0, 0.0, 192501, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("勝ったよ！", "2020/07/31 12:00:00", 24011, 502, "", 1, 0.0, "2030/12/17 14:59:59", 0.0, 0.0, 192501, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("いい調子！", "2020/07/31 12:00:00", 24012, 503, "", 1, 0.0, "2030/12/17 14:59:59", 0.0, 0.0, 192501, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", "2020/07/31 12:00:00", 24013, 111, "ミサト", 2, 0.0, "2030/12/17 14:59:59", 5.33, 0.0, 113501, 6, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", "2020/07/31 12:00:00", 24014, 112, "ミサト", 2, 0.0, "2030/12/17 14:59:59", 6.85, 0.0, 113501, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", "2020/07/31 12:00:00", 24015, 113, "ミサト", 2, 0.0, "2030/12/17 14:59:59", 3.0, 0.0, 113501, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", "2020/07/31 12:00:00", 24016, 611, "ダイチ", 2, 0.0, "2030/12/17 14:59:59", 6.11, 0.0, 192401, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", "2020/07/31 12:00:00", 24017, 612, "ダイチ", 2, 0.0, "2030/12/17 14:59:59", 6.75, 0.0, 192401, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", "2020/07/31 12:00:00", 24018, 613, "ダイチ", 2, 0.0, "2030/12/17 14:59:59", 0.0, 0.0, 192401, 2, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", "2020/07/31 12:00:00", 24019, 211, "ハツネ", 1, 0.0, "2030/12/17 14:59:59", 4.52, 0.0, 113401, 2, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", "2020/07/31 12:00:00", 24020, 212, "ハツネ", 1, 0.0, "2030/12/17 14:59:59", 3.89, 0.0, 113401, 2, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", "2020/07/31 12:00:00", 24021, 213, "ハツネ", 2, 0.0, "2030/12/17 14:59:59", 13.49, 0.0, 113401, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", "2020/07/31 12:00:00", 24022, 311, "カヤ", 2, 0.0, "2030/12/17 14:59:59", 3.17, 0.0, 106501, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", "2020/07/31 12:00:00", 24023, 312, "カヤ", 2, 0.0, "2030/12/17 14:59:59", 4.42, 0.0, 106501, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", "2020/07/31 12:00:00", 24024, 313, "カヤ", 1, 0.0, "2030/12/17 14:59:59", 2.89, 0.0, 106501, 6, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", "2020/07/31 12:00:00", 24025, 421, "アヤネ", 3, 0.0, "2030/12/17 14:59:59", 3.71, 0.0, 102301, 4, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", "2020/07/31 12:00:00", 24026, 721, "アサヒ", 1, 0.0, "2030/12/17 14:59:59", 5.1, 0.0, 192201, 2, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", "2020/07/31 12:00:00", 24027, 821, "部員３", 3, 0.0, "2030/12/17 14:59:59", 4.34, 0.0, 192301, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("いい勝負だったよ\nまたやろうね", "2020/07/31 12:00:00", 24028, 521, "", 1, 0.0, "2030/12/17 14:59:59", 0.0, 0.0, 192501, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", "2020/07/31 12:00:00", 24029, 101, "ミサト", 2, 0.0, "2030/12/17 14:59:59", 5.62, -360.0, 113501, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", "2020/07/31 12:00:00", 24030, 102, "ミサト", 2, 0.0, "2030/12/17 14:59:59", 9.58, -360.0, 113501, 1, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", "2020/07/31 12:00:00", 24031, 103, "ミサト", 2, 0.0, "2030/12/17 14:59:59", 0.0, -360.0, 113501, 2, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", "2020/07/31 12:00:00", 24032, 104, "ミサト", 1, 0.0, "2030/12/17 14:59:59", 9.13, -360.0, 113501, 2, 24, 10046);
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", "2020/07/31 12:00:00", 24033, 105, "ミサト", 2, 0.0, "2030/12/17 14:59:59", 8.27, -360.0, 113501, 1, 24, 10046);
